        "writable": false,
        "enumerable": false,
        "configurable": true
    },
    "arguments": {
        "value": null,
        "writable": false,
        "enumerable": false,
        "configurable": false
    },
    "caller": {
        "value": null,
        "writable": false,
        "enumerable": false,
