*/

// __proto__는 square 함수의 프로퍼티가 아니다.
console.log(Object.getOwnPropertyDescriptor(square, '__proto__')); // undefined

// __proto__는 Object.prototype 객체의 접근자 프로퍼티다.
// square 함수는 Object.prototype 객체로부터 __proto__ 접근자 프로퍼티를 상속받는다.

console.log(Object.getOwnPropertyDescriptor(Object.prototype, '__proto__'));
// {get: f, set: f, enumerable: false, configurable: true}
```

#### 18.2.1 arguments 프로퍼티

> arguments 객체는 함수 호출 시 전달된 `인수(arguments)`들의 정보를 담고 있는 **순회 가능한 유사 배열 객체**이며, **함수 내부에서 지역 변수처럼 사용**된다. 즉, 함수 외부에서는 참조할 수 없다.

자바스크립트는 함수의 매개변수와 인수의 개수가 일치하는지 확인하지 않는다. 따라서 함수 호출 시 매개변수 개수만큼 인수를 전달하지 않아도 에러가 발생하지 않는다.

```cs
function multiply(x, y) {
  console.log(arguments);
  return x + y;
}

console.log(multiply()); // NaN
console.log(multiply(1)); // NaN
console.log(multiply(1, 2)); // 2
console.log(multiply(1, 2, 3)); // 2,
// 초과된 인수는 암묵적으로 arguments 객체의 프로퍼티로 보관된다.
```

- arguments 객체: 인수를 프로퍼티 값으로 소유하며 프로퍼티 키는 인수의 순서를 나타낸다
  - callee 프로퍼티: arguments 객체를 생성한 함수, 즉 함수 자신을 가리킴
  - length 프로퍼티: 인수의 개수

```cs
[ 💡 arguments 객체의 Symbol(Symbol.iterator) 프로퍼티 ]
Symbol(Symbol.iterator) 프로퍼티는 arguments 객체를 순회 가능한 자료구조인 iterable을 만들기 위한 프로퍼티다. Symbol.iterator를 프로퍼티 키로 사용한 메서드를 구현하는 것에 의해 이터러블이 된다.

function multiply(x, y) {
  const iterator = arguments[Symbol.iterator]();

  // 이터레이터의 next 메서드를 호출하여 이터러블 객체 arguments를 순회
  console.log(iterator.next()); // {value: 1, done: false}
  console.log(iterator.next()); // {value: 2, done: false}
  console.log(iterator.next()); // {value: 3, done: false}
  console.log(iterator.next()); // {value: undfined, done: true}

  return x + y;
}
multiply(1, 2, 3);
```

- arguments 객체는 매개변수 개수를 확정할 수 없는 **가변 인자 함수**를 구현할 때 유용하다.

```cs
function sum() {
  let res = 0;

  // arguments 객체는 length 프로퍼티가 있는 유사 배열 객체이므로 for문으로 순회할 수 있다.
  for (let i = 0; i < arguments.length; i++) {
    res += arguments[i];
  }

  return res;
}

console.log(sum()); // 0
console.log(sum(1, 2)); // 3
console.log(sum(1, 2, 3)); // 6
```

- arguments 객체는 배열 형태로 인자 정보를 담고 있지만 실제 배열이 아닌 유사배열객체다.
- 유사배열객체란 length 프로퍼티를 가진 객체로 for문으로 순회할 수 있는 객체를 말한다.

```cs
ES6에서 도입된 이터레이션 프로토콜을 준수하면 순회 가능한 자료구조인 이터러블이 된다.
이터러블의 개념이 없었던 ES5에서 arguments 객체는 유사 배열 객체로 구분되었다.
하지만 이터러블이 도입된 ES6부터 arguments 객체는 유사 배열 객체이면서 동시에 이터러블이다.
```

유사 배열 객체는 배열이 아니므로 배열 메서드를 사용할 경우 에러가 발생한다.
따라서 배열 메서드를 사용하려면 `Function.prototype.call`, `Function.prototype.apply`를 사용해 간접 호출해야 하는 번거로움이 있다.

```cs
function sum() {
  // arguments 객체를 배열로 변환
  const array = Array.prototype.slice.call(arguments);
  return array.reduce(function (pre, cur) {
    return pre + cur;
  }, 0);
}

console.log(sum(1, 2)); // 3
console.log(sum(1, 2, 3, 4, 5)); // 15
```

이런 번거로움을 해결하기 위해 ES6에서는 Rest 파라미터를 도입했다.

```cs
function sum(...args) {
  return args.reduce((pre, cur) => pre + cur, 0);
}

console.log(sum(1, 2)); // 3
console.log(sum(1, 2, 3, 4, 5)); // 15
```

#### 18.2.2 caller 프로퍼티

- 함수 자신을 호출한 함수를 가리킨다

#### 18.2.3 length 프로퍼티

- 함수를 정의할 때 선언한 매개변수의 개수를 가리킨다.
- arguments 객체의 length 프로퍼티는 인자의 개수를 가리킨다. (구별할것)

#### 18.2.4 name 프로퍼티

- 함수 이름을 나타낸다.
- ES5, ES6에서 동작을 달리한다. 익명함수 표현식의 경우, ES5에서 name 프로퍼티는 빈 문자열을 값으로 갖는다. 하지만 ES6에서는 함수 객체를 가리키는 식별자를 값으로 갖는다.

```cs
// 기명 함수 표현식
var namedFunc = function foo() {};
console.log(namedFunc.name); // foo

// 익명 함수 표현식
var anonymousFunc = function() {};
// ES5: name 프로퍼티는 빈 문자열을 값으로 갖는다.
// ES6: name 프로퍼티는 함수 객체를 가리키는 변수 이름을 값으로 갖는다.
console.log(anonymousFunc.name); // anonymousFunc

// 함수 선언문(Function declaration)
function bar() {}
console.log(bar.name); // bar
```

#### 18.2.5 `__proto__` 접근자 프로퍼티

- 모든 객체는 [[Prototype]]이라는 내부 슬롯을 갖는다. [[Prototype]] 내부 슬롯은 객체 지향 프로그래밍의 상속을 구현하는 프로토타입 객체를 가리킨다.
- `__proto__` 프로퍼티는 [[Prototype]] 내부 슬롯이 가리키는 프로토타입 객체에 접근하기 위해 사용하는 접근자 프로퍼티다.

```cs
const obj = {a: 1};

// 객체 리터럴 방식으로 생성한 객체의 프로토타입 객체는 Object.prototype이다.
cosnole.log(obj.__proto__ === Object.prototype); // true

// 객체 리터럴 방식으로 생성한 객체는 프로토타입 객체인 Object.prototype의 프로퍼티를 상속받는다.
// hasOwnProperty 메서드는 OBject.prototype의 메서드다.
console.log(obj.hasOwnProperty('a')); // true
console.log(obj.hasOwnProperty('__proto__')); // false
```

```cs
[ hasOwnProperty ]
인수로 전달받은 프로퍼티 키가 객체 고유의 프로퍼티 키인 경우에만 true를 반환하고
상속받은 프로토타입의 프로퍼티 키인 경우 false를 반환한다.
```

#### 18.2.6 prototype 프로퍼티

- 함수가 객체를 생성하는 생성자 함수로 호출될 때 생성자 함수가 생성할 인스턴스의 프로토타입 객체를 가리킨다.
- 생성자 함수로 호출할 수 있는 함수 객체, 즉 constructor만이 소유하는 프로퍼티다.
- 일반 객체와 생성자 함수로 호출할 수 없는 non-constructor에는 prototype이 없다.

```cs
// 함수 객체는 prototype 프로퍼티를 소유한다.
(function () {}).hasOwnProperty('prototype'); // -> true

// 일반 객체는 prototype 프로퍼티를 소유하지 않는다.
({}).hasOwnProperty('prototype'); // -> false
```

### 17.1 Object 생성자 함수

---

new 연산자와 함께 Object 생성자 함수를 호출하면 빈 객체를 생성하여 반환한다.
빈 객체를 생성한 이후 프로퍼티 또는 메서드를 추가하여 객체를 완성할 수 있다.

```cs
// 빈 객체의 생성
const person = new Object();

// 프로퍼티 추가
person.name = 'Lee';
person.sayHello = function() {
  console.log('Hi! My name is '+ this.name);
};

console.log(person); // {name: 'Lee', sayHello: f}
person.sayHello(); // Hi! My name is Lee
```

> 생성자 함수(constructor)란 new 연산자와 함께 호출하여 객체(인스턴스)를 생성하는 함수를 말한다.

- 인스턴스(instance): 생성자 함수에 의해 생성된 객체
- 자바스크립트는 Object 생성자 함수 이외에도 String, Number, Boolean, Function, Array, Date, RegExp, Promise 등의 빌트인(built-in) 생성자 함수를 제공한다.

```cs
// String 생성자 함수에 의한 String 객체 생성
const strObj = new String('Lee');
console.log(typeof strObj); // object
console.log(strObj);        // String ["Lee"]

const numObj = new Number(123);
const boolObj = new Boolean(true);
const func = new Function('x', 'return x + x');
const arr = new Array(1, 2, 3);
const regExp = new RegExp(/ab+c/i);
const date = new Date();
```

반드시 Object 생성자 함수를 사용해 빈 객체를 생성해야 하는 것은 아니다.
객체를 생성하는 방법은 **객체 리터럴을 사용하는 것이 더 간편**하다.

그러면 Object 생성자 함수는 왜 쓰는 걸까?

### 17.2 생성자 함수

---

### 17.2.1. 객체 리터럴에 의한 객체 생성 방식의 문제점

- 객체 리터럴에 의한 객체 생성방식은 직관적이고 간편하다.
- 하지만 객체 리터럴에 의한 객체 생성 방식은 **단 하나의 객체만 생성**한다.

> 💩 객체 리터럴로 표현하는 경우, 프로퍼티의 구조가 동일함에도 불구하고,
> 매번 같은 프로퍼티와 매서드를 기술해야 한다

```cs

const circle1 = {
  radius: 5,
  getDiameter() { // 매서드
    return 2 * this.radius;
  }
};

console.log(circle1.getDiameter()); // 10

const circle2 = {
  radius: 10,
  getDiameter() {
    return 2 * this.radius;
  }
};

console.log(circle2.getDiameter()); // 20
```

- `객체`는

  - `프로퍼티`를 통해 객체 고유의 `상태(status)`를 표현한다.
  - `메서드`를 통해 상태 데이터인 *프로퍼티를 참조*하고 조작하는 `동작(behavior)`을 표현한다.

- 상태(state)는 객체마다 각기 다른 값을 가질 수 있으나
- 메서드(behavior)의 경우는 내용이 동일한 경우가 일반적이다 -> `재활용성이 필요`

### 17.2.2. 생성자 함수에 의한 객체 생성 방식의 장점

> ✅ `객체(인스턴스)`를 생성하기 위한 `템플릿(클래스)`처럼 `생성자 함수를 사용`하여
> 프로퍼티 구조가 동일한 객체 여러개를 간편하게 생성할 수 있다.

```cs
// 생성자 함수
function Circle(radius) {
  // 생성자 함수 내부의 this는 생성자 함수가 생성할 인스턴스를 가리킨다.
  this.radius = radius;
  this.getDiameter = function () {
    return 2 * this.radius;
  }
}

// 인스턴스의 생성
const circle1 = new Circle(5); // 반지름이 5인 Circle 객체를 생성
const circle2 = new Circle(10); // 반지름이 10인 Circle 객체를 생성

console.log(circle1.getDiameter()); // 10
console.log(circle2.getDiameter()); // 20
```

#### 자바스크립트의 생성자 함수

- 생성자 함수는 `객체(인스턴스)를 생성`하는 함수다.
- 자바 같은 클래스 기반 객체 지향 언어와는 다르게 형식이 정해져 있지 않고
  - **일반 함수와 동일한 방법으로** 생성자 함수를 정의하고
  - **new 연산자**와 함께 호출하면
  - 해당 함수는 생성자 함수로 동작한다.

만약 new 연산자와 함께 생성자 함수를 호출하지 않으면 생성자 함수가 아니라 일반 함수로 동작한다.

```cs
// new 연산자와 함께 호출하지 않으면 생성자 함수로 동작하지 않는다.
// 즉, 일반 함수로서 호출된다.
const circle3 = Circle(15);

// 일반 함수로서 호출된 Circle은 반환문이 없으므로 암묵적으로 undefined를 반환한다.
console.log(circle3); // undefined

// 일반 함수로서 호출된 Circle 내의 this는 전역 객체를 가리킨다.
console.log(radius); // 15
```

### this

this는 객체 자신의 프로퍼티나 메서드를 참조하기 위한 `자기 참조 변수(self-referencing variable)`다. this가 가리키는 값, 즉 this 바인딩은 함수 호출 방식에 따라 동적으로 결정된다.

| 함수 호출방식        | this가 가리키는 값(this 바인딩)        |
| -------------------- | -------------------------------------- |
| 일반 함수로서 호출   | 전역 객체                              |
| 메서드로서 호출      | 메서드를 호출한 객체(마침표 앞의 객체) |
| 생성자 함수로서 호출 | 생성자 함수가 (미래에) 생성할 인스턴스 |

```cs
[ ✅ 함수는 다양한 방식으로 호출될 수 있다. ]
function foo() {
  console.log(this);
}

// 1️⃣ 일반적인 함수로서 호출
// 전역 객체는 브라우저 환경에서는 window, Node.js 환경에서는 global을 가리킨다.

foo(); // window

const obj = { foo }; // ES6 프로퍼티 축약 표현

// 2️⃣ 매서드로서 호출
obj.foo(); // obj

// 3️⃣ 생성자 함수로서 호출
const inst = new foo(); // inst
```

### 17.2.3. 생성자 함수의 인스턴스 생성과정

#### 생성자 함수의 역할

- **[`필수`]** 프로퍼티 구조가 동일한 인스턴스를 생성하기 위한 `템플릿(클래스)`로서 동작하여 인스턴스를 생성하는 것
- **[`옵션`]** 생성된 **인스턴스를 초기화**(`인스턴스 프로퍼티 추가 및 초기값 할당`)하는 것

this에 프로퍼티를 추가하고, 필요에 따라 전달된 인수를 프로퍼티의 초기값으로서 할당하여 인스턴스를 초기화 한다.

```cs
// 생성자 함수
function Circle(radius) {
  // 인스턴스 초기화
  this.radius = radius;
  this.getDiameter = function () {
    return 2 * this.radius;
  }
}

const circle1 = new Circle(5); // 반지름이 5인 Circle 객체를 생성
```

하지만 **인스턴스를 생성하고 반환하는 코드**는 보이지 않는다.

> new 연산자와 함께 생성자 함수를 호출하면 자바스크립트 엔진은 암묵적인 처리를 통해 인스턴스를 생성하고 반환한다.

#### 1. 인스턴스 생성과 this 바인딩

- 암묵적으로 빈 객체가 생성된다.
- 이 빈 객체가 `생성자 함수`가 생성한 `인스턴스`다.
- 이 빈 객체(인스턴스)는 `this에 바인딩` 된다.
  - binding: 식별자와 값을 연결하는 과정
  - this에 바인딩: this와 this가 가리킬 객체를 바인딩 하는 것

```cs
function Circle(radius) {
  // 1. 암묵적으로 인스턴스가 생성되고 this에 바인딩 된다.
  console.log(this); // Circle{}
  ...
}
```

#### 2. 인스턴스 초기화

- 생성자 함수에 기술되어 있는 코드가 한 줄씩 실행되어 **this에 바인딩되어 있는 인스턴스를 초기화** 한다.
- this에 바인딩되어 있는 인스턴스에 `프로퍼티나 메서드를 추가`하고 생성자 함수가 `인수로 전달받은 초기값을 인스턴스 프로퍼티에 할당`하여 초기화하거나 고정값을 할당한다.

```cs
// 생성자 함수 Person 선언
function Person(name) {
  // 1. 암묵적으로 빈 객체(인스턴스)가 생성되고 this에 바인딩

  // 2. this 에 바인딩되어 있는 인스턴스를 초기화
  this.name = name;
  this.getPersonName = function () {
    return `Hi, My Name is ${this.name}`;
  };
}

```

#### 3. 인스턴스 반환

- 생성자 함수 내부에서 모든 처리가 끝나면 완성된 인스턴스가 바인딩된 this를 암묵적으로 반환한다.

```cs
// 생성자 함수 Person 선언
function Person(name) {
  // 1. 암묵적으로 빈 객체(인스턴스)가 생성되고 this에 바인딩

  // 2. this 에 바인딩되어 있는 인스턴스를 초기화
  this.name = name;
  this.getPersonName = function () {
    return `Hi, My Name is ${this.name}`;
  };

  // 3. 완성된 인스턴스가 바인딩된 this(= 인스턴스)가 암묵적으로 반환된다.
  // 💩 명시적으로 원시값을 반환하면 원시값 반환은 무시되고 암묵적으로 this가 반환된다.
  return 100;
  // 💩 this가 아닌 다른 객체를 명시적으로 반환하면 this가 반환되지 못하고 return문에 명시한 객체가 반환된다
  return {}
}

// 인스턴스를 생성, Person 생성자 함수는 암묵적으로 this(Person 인스턴스)를 반환한다.
const person = new Person("Kim");
console.log(person);
// Person { name: 'Kim', getPersonName: [Function (anonymous)] }
```

> 결론적으로, 생성자 함수 내부에서 명시적으로 `this가 아닌 다른 값을 반환`하는 것은, 생성자 함수의 기본 동작을 훼손하는 것이므로, 반드시 `생성자 함수 내부에서는 return 문을 생략할 것`

### 17.2.4. 내부 메서드 [[Call]] 과 [[Construct]]

- 함수 선언문 또는 함수 표현식으로 정의한 함수는
  - 일반적인 함수로서 호출할 수 있는 것은 물론 생성자 함수로서 호출할 수 있다.
- 생성자 함수로서 호출한다는 것은 new 연산자와 함께 호출하여 객체를 생성하는 것을 의미한다
- 함수는 객체이므로 일반 객체와 동일하게 동작할 수 있다.
  - 일반 객체가 가지고 있는 내부 슬롯, 내부 메서드를 모두 가지고 있기 때문

```cs
// 함수는 객체다
function foo() {}

// 함수는 객체이므로 프로퍼티를 소유할 수 있다.
foo.prop = 10;

// 함수는 객체이므로 메서드를 소유할 수 있다.
foo.method = function () {
  console.log(this.prop);
};

foo.method(); // 10
```

- 일반 객체는 호출할 수 없지만 함수는 호출할 수 있다.
- 따라서 함수 객체는 일반 객체가 가지고 있는 내부 슬롯과 내부 메서드는 물론
  - 함수 객체만을 위한 [[Environment]], [[FormalParameters]] 등의 내부 슬롯과 [[Call]], [[Construct]] 같은 내부 메서드를 추가로 가지고 있다.

### [[Call]] 과 [[Construct]]

```cs
function foo() {}

// 일반적인 함수로서 호출: [[Call]]이 호출된다.
foo();

// 생성자 함수로서 호출: [[Construct]]가 호출된다
new foo();
```

- 내부 메서드 [[Call]] 을 갖는 함수 객체 → `callable`
- 내부 메서드 [[Construct]] 을 갖는 함수 객체 → `constructor`
  - 내부 메서드 [[Construct]] 을 갖지 않는 함수 객체 → `non-constructor`

### constructor 와 non-constructor

> 생성자 함수로 호출한다는 것 = `new 연산자`와 함께 호출하여 `객체를 생성`한다는 것

- `constructor` = 생성자 함수로 호출할 수 있는 형태 : `함수 선언문`, `함수 표현식`
- `non-constructor` = 생성자 함수로 호출할 수 없는 형태: `화살표 함수`, `매서드(ES6 메서드 축약 표현)`
  - non-constructor인 함수 객체를 생성자 함수로서 호출하면 에러가 발생한다.

![모든 함수 객체는 callable이지만 모든 함수 객체가 constructor인 것은 아니다.](image.png)

```cs
// 일반 함수 정의: 함수 선언문, 함수 표현식
function foo() {}
const bar = function () {};
// 프로퍼티 x의 값으로 할당된 것은 일반 함수로 정의된 함수다. 이는 메서드로 인정하지 않는다.
const baz = {
  x: function () {}
};

// 일반 함수로 정의된 함수만이 constructor다.
new foo(); // -> foo {}
new bar(); // -> bar {}
new baz.x(); // -> x {}

// 화살표 함수 정의
const arrow = () => {};

new arrow(); // TypeError: arrow is not a constructor

// 메서드 정의: ES6의 메서드 축약 표현만 메서드로 인정한다.
const obj = {
  x() {}
};

new obj.x(); // TypeError: obj.x is not a constuctor
```

### new 연산자

> new 연산자와 함께 함수를 호출하면 해당 함수가 `생성자 함수`로 동작한다

- 즉, 함수 객체의 내부 메서드 중 `[[ Construct ]]` 가 호출된다는 것
- 단, 이 때 호출되는 함수는 `non-constructor` 가 아닌 `constructor` 여야한다는 것

```cs
// 생성자 함수 선언
function Person(name) {
  // ✅ PascalCase: 생성자 함수를 생성하여 일반함수와 구분한다!!!
  this.name = name;
  this.getPersonName = function () {
    return this.name;
  };
}

// 일반 함수가 new 연산자와 함께, 생성자 함수로 호출
const person = new Person("Kim");
console.log(person); // Person { name: 'Kim', getPersonName: [Function~]}
```

- 반대로 new 연산자 없이, 생성자 함수를 호출하면 일반 함수로 호출된다.
  - 즉, 함수 객체의 내부 메서드 [[Constuct]]가 호출되는 것이 아니라 [[Call]]이 호출된다.

```cs
// 생성자 함수가 new 연산자 없이, 일반 함수로 호출
const person = Person("WI");
console.log(person); // undefined << 🔍 반환 값이 없으므로 결과는 undefined
```

### new.target

> ES6에 도입되어, new 연산자와 함께 생성자 함수로서 호출되었는지 확인할 수 있는 문법

- `new 연산자`와 함께 `생성자 함수`로서 호출되면 함수 내부의 new.target은 **함수 자신을 가리킨다**.
- `new 연산자 없이` `일반 함수`로서 호출된 함수 내부의 new.target은 **undefined를 가리킨다**.

```cs
// 생성자 함수 Person 선언
function Person(name) {
  // Person 생성자 함수가 호출되면, 가장 먼저 new 연산자와 함께 호출된 것인지 확인
  if(!new.target) {
    // new 키워드와 함께 호출된 것이 아니면, 함수 내부에서 재귀로 new 연산자와 함께
    // Person 생성자 함수를 호출
    return new Person(name);
  }

  this.name = name;
  this.getPersonName = function () {
    return this.name;
  };
}

// new 연산자 없이 생성자 함수를 호출
const person = Person("Kim");

// 그럼에도 불구하고, Person 인스턴스가 정상적으로 생성되었고, 내부 매서드 호출됨
console.log(person.getPersonName()); // Kim
```

### 스코프 세이프 생성자 패턴(Scope-safe constructor)

> IE 같은 new.target 을 지원하지 않는 브라우저 환경에서, 생성자 함수를 보장하는 방법

```cs
function Person(name) {
  // Person 생성자 함수가 new 연산자와 함께 호출되지 않는 경우,
  // this는 전역 객체 window를 가리킨다
  // 즉 this는 Person과 프로포타입에 의해 연결되지 않는다.
  if(!(this instanceof Person)) {
    // new 연산자와 함께 호출된 Person 인스턴스를 반환하도록 재귀호출 한다.
    return new Person(name);
  }

  this.name = name;
  this.getPersonName = function() {
    return this.name;
  }
}

// new 연산자 없이 생성자 함수를 호출
const person = Person("Kim");

// 그럼에도 불구하고, Person 인스턴스가 정상적으로 생성되었고, 내부 매서드 호출됨
console.log(person.getPersonName()); // Kim
```

- new 연산자와 함께 생성자 함수에 의해 생성된 객체(인스턴스)는 프로토타입에 의해 생성자 함수와 연결된다.
- 이를 이용해 new 연산자와 함께 호출되었는지 확인할 수 있다.

- 대부분의 빌트인 생성자 함수(Object, String, Number, Boolean, Function, Array, Date, RegExp, Promise 등)는 new 연산자와 함께 호출되었는지를 확인한 후 적절한 값을 반환한다.

예를 들어, Object와 Function 생성자 함수는 new 연산자 없이 호출해도 new 연산자와 함께 호출했을 때와 동일하게 동작한다.

```cs
let obj = new Object(); // {}
obj = Object(); // {}

let f = new Function('x', 'return x ** x');
f = Function('x', 'return x ** x');
```

String, Number, Boolean 생성자 함수는 new 연산자와 함께 호출했을 때 String, Number, Boolean 객체를 생성하여 반환하지만 new 연산자 없이 호출하면 문자열, 숫자, 불리언 값을 반환한다.
이를 통해 데이터 타입을 변환하기도 한다.

### 16.1 내부 슬롯(Internal Slot)과 내부 메서드(Internal Method)

---

- 자바스크립트 엔진의 구현 알고리즘을 설명하기 위해 ECMAScript 사양에서 사용하는 `의사 프로퍼티(pseudo property)`와 `의사 메서드(pseudo method)`다.
- `내부 슬롯 & 내부 메서드` 는 자바스크립트 엔진에서 실제로 동작은 하지만 개발자가 직접 접근할 수 있도록 외부로 공개된 객체의 프로퍼티는 아니다.
- 즉, 자바스크립트 엔진의 `내부 로직` 이므로 자바스크립트로 직접 접근하거나 호출할 수 있는 방법을 제공하진 않는다.
- 단, 일부 내부 슬롯 & 메서드에 대해서는 접근할 수 있는 수단을 제공한다.
  - 예를 들어 `[[Prototype]]` 내부 슬롯은 `__proto__` 를 통해 간접 접근 가능

```cs
const o = {};

// 내부 슬롯은 자바스크립트 엔진의 내부 로직이므로 직접 접근할 수 없다.
o.[[Prototype]] // Uncaught SyntaxError: Unexpected token '['
// 단, 일부 내부 슬롯과 내부 메서드에 한하여 간접적으로 접근할 수 있는 수단을 제공하기는 한다.
o.__proto__ // Object.prototype
```

### 16.2 Property Attribute & Property Descriptor Object

---

### Property Attribute

> 자바스크립트 엔진은 프로퍼티를 생성할 때 `프로퍼티의 상태`를 나타내는 `프로퍼티 어트리뷰트`를 기본값으로 자동 정의한다.

- 프로퍼티 상태

  - `프로퍼티의 값(value)`
  - `값의 갱신 가능 여부(writable)`
  - `열거 가능 여부(enumerable)`
  - `재정의 가능 여부(configurable)`

- 프로퍼티 어트리뷰트에 직접 접근할 수 없지만 `Object.getOwnPropertyDescriptor(객체의 참조, property key)` 메서드를 사용하여 간접적으로 확인할 수는 있다.

```cs
const person = {
  name: 'Lee'
};

// 프로퍼티 어트리뷰트 정보를 제공하는 프로퍼티 디스크립터 객체를 반환한다.
console.log(Object.getOwnPropertyDescriptor(person, 'name'));
// {value: 'Lee', writable: true, enumerable: true, configurable: true}

```

- 객체: `객체의 참조(Reference)`를 전달
- 프로퍼티 키: `문자열 or 심벌`을 전달

### Property Descriptor Object

> 프로퍼티 어트리뷰트 정보를 제공하는 객체

- 존재하지 않는 프로퍼티나 상속받은 프로퍼티에 대한 프로퍼티 디스크립터를 요구하면 -> undefined 반환
- 기본적으로 하나의 프로퍼티에 대해 프로퍼티 디스크립터 객체를 반환

  - ES8에 모든 프로퍼티의 `프로퍼티 어트리뷰트 정보`를 제공하는 프로퍼티 디스크립터 객체를 반환할 수 있게 되었다.

  ```cs
  const person = {
    name: 'Lee'
  };

  // 프로퍼티 동적 생성
  person.age = 20;

  // 모든 프로퍼티의 프로퍼티 어트리뷰트 정보를 제공하는 프로퍼티 디스크립터 객체를 반환한다.
  console.log(Object.getOwnPropertyDescriptors(person));

  /*
  {
    name: {value: 'Lee', writable: true, enumerable: true, configurable: true},
    age: {value: 20, writable: true, enumerable: true, configurable: true}
  }
  */
  ```

### 16.3 데이터 프로퍼티와 접근자 프로퍼티

---

- 데이터 프로퍼티(data property)
  - 키와 값으로 구성된 일반적인 프로퍼티.
- 접근자 프로퍼티(accessor property)
  - 자체적으로는 값을 갖지 않고 다른 데이터 프로퍼티의 값을 읽거나 저장할 때 호출되는 접근자 함수로 구성된 프로퍼티다.

#### 1. 데이터 프로퍼티

다음과 같은 프로퍼티 어트리뷰트를 갖는다. 자바스크립트 엔진이 프로퍼티를 생성할 때 기본적으로 자동 정의 된다.

| 프로퍼티 어트리뷰트 | 프로퍼티 디스크립터 객체의 프로퍼티 | 설명                                                                                                                                                                                                                                                            |
| ------------------- | ----------------------------------- | --------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- |
| [[Value]]           | value                               | <li> 프로퍼티 키를 통해 프로퍼티 값에 접근하면 반환 되는 값 </li> <li>프로퍼티 키를 통해 프로퍼티 값을 변경하면 [[Value]]에 값을 재할당 한다. 이때 프로퍼티가 없으면 프로퍼티를 동적 생성하고 생성된 프로퍼티의 [[Value]]에 값을 저장한다.</li>                 |
| [[Writable]]        | writable                            | <li>프로퍼티 값 변경 가능 여부 → boolean </li> <li>[[writable]]의 값이 false인 경우 해당 프로퍼티의 [[Value]]값을 변경할 수 없는 읽기 전용 프로퍼티가 된다.</li>                                                                                                |
| [[Enumerable]]      | enumerable                          | <li>프로퍼티의 열거 가능 여부 → boolean </li> <li> false인 경우, `for...in` 문이나 `Object.keys` 메서드 등으로 열거할 수 없다</li>                                                                                                                              |
| [[Configurable]]    | configurable                        | <li>프로퍼티의 재정의 가능 여부 → boolean </li> <li> [[Configurable]]의 값이 false인 경우 해당 프로퍼티의 삭제, 프로퍼티 어트리뷰트 값의 변경이 금지된다. 단, [[Writable]]이 true인 경우 [[value]]의 변경과 [[writable]]을 false로 변경하는 것은 허용된다.</li> |

- 프로퍼티 생성 시
  - [[Value]] 값은 프로퍼티 값으로 초기화
  - [[Writable]], [[Enumerable]], [[Configurable]] 는 모두 true 로 초기화
  - 프로퍼티를 동적 생성 해도 마찬가지로 적용

#### 2. 접근자 프로퍼티

- 자체적으로는 값을 갖지 않고
- 다른 데이터 프로퍼티의 값을 읽거나 저장할 때 사용하는 `접근자 함수`로 구성된 프로퍼티다.
- getter/setter 함수라고도 부른다.

| 프로퍼티 어트리뷰트 | 프로퍼티 디스크립터 객체의 프로퍼티 | 설명                                                                     |
| ------------------- | ----------------------------------- | ------------------------------------------------------------------------ |
| [[Get]]             | get                                 | 데이터 프로퍼티의 값을 읽을 때 호출되는 접근자 함수 → getter 함수 호출   |
| [[Set]]             | set                                 | 데이터 프로퍼티의 값을 저장할 때 호출되는 접근자 함수 → setter 함수 호출 |
| [[Enumerable]]      | enumerable                          | 데이터 프로퍼티의 [[Enumerable]] 와 같다                                 |
| [[Configurable]]    | configurable                        | 데이터 프로퍼티의 [[Configurable]] 와 같다                               |

```cs
const person = {
  // 데이터 프로퍼티
  firstName: 'Jiwoo',
  lastName: 'Kim'

  // getter/setter 함수의 이름 fullName이 접근자 프로퍼티다.
  // property attribute [[value]]를 가지지 않으며 다만 데이터 프로퍼티의 값을 읽거나 저장할 때 관여할 뿐이다.
  // getter 함수
  get fullName() {
    return `${this.firstName} ${this.lastName}`;
  },

  // setter 함수
  set fullName(name) {
    // 배열 디스트럭쳐링 할당: 31.1 배열 디스트럭처링 할당" 참고
    [this.firstName, this.lastName] = name.split('');
  }
};

// 1️⃣ 데이터 프로퍼티를 통한 프로퍼티 값의 참조.
console.log(person.firstName + ' ' + person.lastName); // Jiwoo Kim

// 2️⃣ 접근자 프로퍼티를 통한 프로퍼티 값의 저장
// 접근자 프로퍼티 fullName에 값을 저장하면 setter함수가 호출된다.
person.fullName = 'Lina Kim';
console.log(person); // {firstName: 'Lina', lastName: 'Kim'}

// 접근자 프로퍼티를 통한 프로퍼티 값의 참조
// 접근자 프로퍼티 fullName에 접근하면 getter 함수가 호출된다.
console.log(person.fullName); // Lina Kim

// firstName은 데이터 프로퍼티다.
// 데이터 프로퍼티는 [[Value]], [[Writable]], [[Configurable]]
// 프로퍼티 어트리뷰트를 갖는다.
let descriptor = Object.getOwnPropertyDescriptor(person, 'firstName');
console.log(descriptor);
// {value: 'Lina', writable: true, enumerable: true, configurable: true}

// fullName은 접근자 프로퍼티다.
// 접근자 프로퍼티는 [[Get]], [[Set]], [[Enumerable]], [[Configurable]] 프로퍼티 어트리뷰트를 갖는다.
descriptor = Object.getOwnPropertyDescriptor(person, 'fullName');
console.log(descriptor);
// {get: f, set: f, enumerable: true, configurable: true}
```

**접근자 프로퍼티 fullName으로 프로퍼티 값에 접근하면 내부적으로 [[Get]] 내부 메서드가 호출되어 다음과 같이 동작한다.**

```cs
1️⃣ 프로퍼티 키가 유효한지 확인한다. 프로퍼티 키는 문자열 또는 심벌이어야 한다.
2️⃣ 프로토타입 체인에서 프로퍼티를 검색한다. person 객체에 fullName 프로퍼티가 존재한다.
3️⃣ 검색된 fullName 프로퍼티가 데이터 프로퍼티인지 접근자 프로퍼티인지 확인한다.
fullName 프로퍼티는 접근자 프로퍼티다.
4️⃣ 접근자 프로퍼티 fullName의 프로퍼티 어트리뷰트 [[Get]]의 값, 즉 getter 함수를 호출하여 그 결과를 반환한다.
```

```cs
[ 💡 Prototype ]

'프로토타입'은 어떤 객체의 상위(부모) 객체의 역할을 하는 객체다.
프로토타입은 하위(자식) 객체에게 자신의 프로퍼티와 메서드를 상속한다.
이를 상속받은 하위 객체는 자신의 프로퍼티 또는 메서드인 것 처럼 자유롭게 사용할 수 있다.

'프로토타입 체인'은 프로토타입이 단방향 링크드리스트 형태로 연결되어 있는 상속구조를 말한다.
객체의 프로퍼티나 메서드에 접근하려고 할 때 해당 객체에 접근하려는 프로퍼티 또는 메서드가 없다면
프로토타입 체인을 따라 프로토타입의 프로퍼티나 메서드를 차례대로 검색한다.
```

**접근자 프로퍼티와 데이터 프로퍼티를 구별하는 방법**

```cs
// 일반 객체의 __proto__는 접근자 프로퍼티다.
Object.getOwnPropertyDescriptor(Object.prototype, '__proto__');
// {get: f, set: f, enumerable: false, configurable: true}

// 함수 객체의 prototype은 데이터 프로퍼티다.
Object.getOwnPropertyDescriptor(function() {}, 'prototype');
// {value: {...}, writable: true, enumerable: false, configurable: true}
```

### 16.4 프로퍼티 정의

---

> 새로운 프로퍼티를 추가하면서 property attribute를 명시적으로 정의하거나,
> 기존 프로퍼티의 property attribute를 재정의하는 것을 말한다.

- 프로퍼티 값을 갱신(writable) 가능하도록 할 것인지
- 프로퍼티를 열거(enumerable) 가능하도록 할 것인지
- 프로퍼티를 재정의(configurable) 가능하도록 할 것인지
  - 객체의 프로퍼티가 어떻게 동작해야 하는지를 명확히 정의할 수 있다.

`Object.defineProperty` 메서드를 사용하면 프로퍼티의 attribute를 정의할 수 있다.

- 한번에 하나의 프로퍼티만 정의할 수있다.
- `Object.defineProperties`를 사용하면 여러 개의 프로퍼티를 한 번에 정의할 수 있다.

- 인수로는 `객체의 참조`, `데이터 프로퍼티의 key`인 문자열, `property descriptor object`를 전달

```cs
const person = {};

// 데이터 프로퍼티 정의
Object.defineProperty(person, 'firstName', {
  value: 'Jiwoo',
  writable: true,
  enumerable: true,
  configurable: true
});

Object.defineProperty(person, 'lastName', {
  value: 'Kim'
});

let descriptor = Object.getOwnPropertyDescriptor(person, 'firstName');
console.log('firstName', descriptor);

// 디스크립터 객체의 프로퍼티를 누락시키면 undefined, false가 기본값이다.
descriptor = Object.getOwnPropertyDescriptor(person, 'lastName');
console.log('lastName', descriptor);

```

### 16.5 객체 변경 방지

---

- 객체는 변경 가능한 값이므로 재할당 없이 직접 변경할 수 있다.
  - 프로퍼티를 추가, 삭제, 값 갱신 모두 할 수 있다.
  - `object.defineProperty` or `object.defineProperties` 메서드를 사용하여 프로퍼티 어트리뷰트를 재정의할 수도 있다.

> 그러나 객체를 변경하지 말아야할 경우가 존재하고, 이를 지원하는 메서드를 제공한다.

- 객체 변경 방지 메서드 들은 금지하는 강도가 다르다.
- `strict mode`에서 **허용하지 않는 프로퍼티 제어 동작**에 대해서는 `에러를 발생시킴`
- `strict mode`가 아닌 경우에서는 해당 명령을 무시한다.

| 구분           | 메서드                   | 프로퍼티 추가 | 프로퍼티 삭제 | 프로퍼티 값 읽기 | 프로퍼티 값 쓰기 | 프로퍼티 어트리뷰트 재정의 |
| -------------- | ------------------------ | ------------- | ------------- | ---------------- | ---------------- | -------------------------- |
| 객체 확장 금지 | Object.preventExtensions | X             | O             | O                | O                | O                          |
| 객체 밀봉      | Object.isSealed          | X             | X             | O                | O                | X                          |
| 객체 동결      | Object.freeze            | X             | X             | O                | X                | X                          |

#### 1. 객체 확장 금지

확장이 금지된 객체는 프로퍼티 추가가 금지된다.

```cs
Object.preventExtensions(객체);

// 확장 가능한 객체인지 판단 여부 메서드 -> boolean
Object.isExtensible(객체);

```

#### 2. 객체 밀봉

밀봉된 객체는 읽기와 쓰기만 가능하다.

```cs
Object.seal(객체);

// 밀봉된 객체인지 판단 여부 메서드 -> boolean
Object.isSealed(객체);

```

#### 3. 객체 동결

동결된 객체는 읽기만 가능하다

```cs
Object.freeze(객체);

// 동결된 객체인지 판단 여부 메서드 -> boolean
Object.isFrozen(객체);
```

#### 4. 불변 객체

위의 변경방지 메서들은 얕은 변경 방지(shallow only)로 직속 프로퍼티만 변경이 방지되고 중첩 객체까지는 영향을 주지 못한다.

그래서 Object.freeze로 객체를 동결해도 중첩 객체까지 동결할 수는 없다.

따라서 중첩객체까지 동결하는 읽기 전용의 불변 객체를 구현하려면 객체를 값으로 갖는 모든 프로퍼티에 대해 재귀적으로 Object.freeze 메서드를 호출해야 한다.

```cs
function deepFreeze(target) {
  // 객체가 아니거나 동결된 객체는 무시하고 객체이고 동결되지 않은 객체만 동결한다.
  if(target && typeof target === 'object' && !Object.isFrozen(target)) {
    Object.freeze(target);
    /*
      모든 프로퍼티를 순회하며 재귀적으로 동결한다.
      Object.keys 메서드는 객체 자신의 열거 가능한 프로퍼티 키를 배열로 반환한다.
    */
    Object.keys(target).forEach(key => deepFreeze(target[key]));
  }
  return target;
}
```

### 15.1 var 키워드로 선언한 변수의 문제점

---

#### 1. 변수 중복 선언 허용

```cs
var x = 1;
var y = 1;

// var 키워드로 선언된 변수는 같은 스코프 내에서 중복 선언을 허용한다.
// 초기화문이 있는 변수 선언문은 자바스크립트 엔진에 의해 var 키워드가 없는 것처럼 동작한다.
var x = 100;
// 초기화문이 없는 변수 선언문은 무시된다.
var y;

console.log(x); // 100
console.log(y); // 1
```

#### 2. 함수 레벨 스코프

- **함수 외부에서 var 키워드로 선언한 변수**는 코드 블록 내에서 선언해도 모두 `전역 변수`가 된다.
  - 함수레벨 스코프
- 함수레벨 스코프는 전역 변수를 남발할 가능성을 높이고, 의도치 않게 전역 변수가 중복 선언되는 경우가 발생한다.

```cs
var x = 1;

if (true) {
  // 코드 블록(블록 레벨), 하지만 var는 함수 레벨 스코프
  // 따라서, 블록 내 x 변수는 전역 변수처럼 스코프가 적용
  var x = 10;
}

console.log(x); // 10
```

#### 3. 변수 호이스팅

```cs
// 1️⃣ 선언 단계 - 이 시점에는 변수 호이스팅에 의해 이미 foo 변수가 선언되었다.
// 2️⃣ 초기화 단계 - 변수 foo는 undefined로 초기화된다.
console.log(foo); // undefined

// 3️⃣ 할당 단계 - 변수에 값을 할당
foo = 123;

console.log(foo); // 123

// 변수 선언은 런타임 이전에 자바스크립트 엔진에 의해 암묵적으로 실행된다.
var foo;
```

### 15.2 let 키워드

---

ES6에 도입되어 var 키워드의 단점을 보완하기 위해 등장했다.

#### 1. 변수 중복 선언 금지

- let 키워드로 이름이 같은 변수를 중복선언하면 `문법 에러(SyntaxError)`가 발생한다.

#### 2. 블록 레벨 스코프

- `var 키워드로 선언한 변수`는 `함수 레벨 스코프`를 따른다.
  - **함수의 코드 블록만을 지역 스코프로 인정**
- `let 키워드로 선언한 변수`는 `블록 레벨 스코프`를 따른다.
  - **모든 코드 블록(함수, if, for, while, try/catch)을 지역스코프로 인정**

```cs
let foo = 1; // 전역 변수

{
  let foo = 2; // 지역 변수
  let bar = 3; // 지역 변수
}

console.log(foo); // 1
console.log(bar); // ReferenceError: bar is not defined

// 같은 스코프의 블록 내에 있는 변수를 참조한다.
```

![블록 레벨 스코프의 중첩](image.png)

#### 3. 변수 호이스팅

var 로 선언한 변수와는 달리 let 으로 선언한 변수는 변수 호이스팅이 발생하지 않는 것처럼 동작한다.

```cs
console.log(foo); // ReferenceError: foo is not defined
let foo;
```

✅ **var로 선언한 변수**
![var 키워드로 선언한 변수의 생명 주기](image-2.png)

- 런타임 이전에 자바스크립트 엔진에 의해 암묵적으로 '선언 단계'와 '초기화 단계'가 한번에 진행된다.
- 즉, `선언 단계`에서 스코프(실행 컨텍스트의 렉시컬 환경)에 변수 식별자를 등록해 자바스크립트 엔진에 변수의 존재를 알린다.
- 그리고 즉시 `초기화 단계`에서 undefined로 변수를 초기화한다.
- 따라서 변수 선언문 이전에 변수에 접근해도 스코프에 변수가 존재하기 때문에 에러가 발생하지 않는다.

✅ **let으로 선언한 변수**

![let 키워드로 선언한 변수의 생명 주기](image-1.png)

- 선언 단계와 초기화 단계가 분리되어 진행된다

```cs
// 1️⃣ 런타임 이전에 선언 단계가 실행된다. 아직 변수가 초기화되지 않았다.
// ReferenceError: foo is not defined
// 💡 일시적 사각지대
console.log(foo);

let foo; // 2️⃣ 변수 선언문에서 초기화 단계가 실행된다.
console.log(foo); // undefined

foo = 1; // 3️⃣ 할당문에서 할당 단계가 실행된다
console.log(foo); // 1
```

#### 호이스팅 하지 않는 것 처럼 보이는 let

```cs
let foo = 1;
{
    console.log(foo); // 호이스팅이 발생하지 않으면 여기서 1을 리턴해야 한다.
    let foo = 2;
    // 하지만 호이스팅이 발생하기 때문에 참조에러가 발생함
    // Uncaught ReferenceError: Cannot access 'foo' before initialization
}
```

> 자바스크립트는 모든 선언 (var, let, const ,function, function\*, class..)를 호이스팅한다.
> 단, let, const, class를 사용한 선언문은 호이스팅이 발생하지 않는 것처럼 동작한다

#### 4. 전역 객체와 let

- var 키워드로 선언한 전역 변수와 전역 함수, 선언하지 않은 변수에 값을 할당한 암묵적 전역은 "전역 객체 window이 프로퍼티"가 된다.
- 전역 객체의 프로퍼티를 참조할 때 window를 생략 가능
- 단, 전역 객체는 "브라우저 환경 내에서 참조 가능"

```cs
// 이 예제는 브라우저 환경에서 실행해야 한다.

var x = 1; // 전역 변수
y = 2; // 암묵적 전역
function foo() {} // 전역 함수

// var 키워드로 선언한 전역 변수는 전역 객체 window의 프로퍼티다.
console.log(window.x); // 1
// 전역 객체 window의 프로퍼티는 전역 변수처럼 사용할 수 있다.
console.log(x); // 1

// 암묵적 전역은 전역 객체 window의 프로퍼티다.
console.log(window.y); // 2
console.log(y); // 2

// 함수 선언문으로 정의한 전역 함수는 전역 객체 window의 프로퍼티다.
console.log(window.foo) // f foo() {}
// 전역 객체 window의 프로퍼티는 전역 변수처럼 사용할 수 있다.
console.log(foo); // f foo() {}
```

- let,const 으로 선언한 전역 변수는 전역 객체의 프로퍼티가 아니다.
  - 즉, window 객체에 접근할 수 없다.
  - 이는 let 전역 변수는 보이지 않는 개념적인 블록 내 (전역 렉시컬 환경의 선언적 환경레코드(DER)에 존재하기 때문

### 15.3 const 키워드

---

> const 키워드 는 상수(constant) 를 선언하기 위해 사용 ( 단, 반드시 상수만을 위해 사용하는 것은 아님 )

- let과 비슷하며 다른 점은 아래와 같다.

#### 1. 선언과 초기화

const 키워드 변수는 반드시 선언과 동시에 초기화를 해야 한다.

```cs
const foo;  // SyntaxError: Missing initializer in const declaration
```

#### 2. 재할당 금지

const 키워드 변수는 재할당이 금지된다.

```cs
const foo = 1;
foo = 2; // TypeError: Assignment to constant variable.
```

#### 3. 상수

- const 키워드로 선언한 변수에 원시 값을 할당한 경우 변수 값을 변경할 수 없다.
- 원시 값은 변경 불가능한 값(immutable value)이므로 재할당 없이 값을 변경할 수 있는 방법이 없기 때문이다.
- 상수도 곧 변수이며, 즉 상수도 메모리 공간을 가지며 값을 가진다.
- 단, 변수는 언제든지 재할당을 통해 변수 값을 변경 가능하지만, 상수는 재할당이 금지될 뿐이다.
- 상수는 상태 유지와 가독성, 유지보수의 편의를 위해 적극적으로 사용을 권장
- 일반적으로 상수의 이름은 `대문자`로 선언 하며, 여러 단어로 이뤄진 경우 `언더 스코어(_)` 로 구분하며 `스네이크 케이스(snakeCase)` 로 표현한다.

```cs
// TAX_RATE 라는 상수(constant)를 적용하므로써, 코드의 가독성이 증가한다.
const TAX_RATE = 0.1;

let preTaxPrice = 100;
let afterTaxPrice = preTaxPrice + preTaxPrice * TAX_RATE;

console.log(afterTaxPrice); // 110
```

#### 4. const 키워드와 객체

- const 키워드 로 선언한 변수에 객체 를 할당한 경우는 변수 값을 변경할 수 있다.
- 객체는 재할당 없이도 직접 값을 변경이 가능하기 때문
- const 키워드 는 재할당을 금지할 뿐 불변 을 의미하지는 않는다

```cs
const person = {
  name: 'Lee';
};

// 객체는 변경 가능한 값이다. 따라서 재할당 없이 변경이 가능하다.
person.name = 'Kim';
console.log(person); // {name: 'Kim'}
```

### 15.4 var vs. let vs. const

---

- ES6를 사용한다면 var 키워드는 사용하지 않는다.
- 재할당이 필요한 경우에 한해 let 키워드를 사용한다. 이때 변수의 스코프는 최대한 좁게 만든다.
- 변경이 발생하지 않고 읽기 전용으로 사용하는(재할당이 필요없는 상수) 원시 값과 객체에는 const 키워드를 사용한다.
- const 키워드는 재할당을 금지하므로 var, let 키워드 보다 안전하다

### 13.1 스코프란?

---

> 모든 식별자(변수 이름, 함수이름, 클래스 이름 등)는 `자신의 선언된 위치`에 의해
> 다른 코드가 식별자 자신을 참조할 수 있는 `유효범위(Scope)`가 결정된다.

- 자바스크립트의 스코트는 다른 언어의 스코프과 구별되는 특징이 있다.
- var 키워드로 선언한 변수와 let, const로 선언한 변수의 스코프도 다르게 동작한다.

```cs
var var1 = 1;

if(true) {
  var2 = 2;
  if(true) {
    var var3 = 3;
  }
}

function foo() {
  var var4 = 4;

  function bar() {
    var var5 = 5;
  }
}

console.log(var1); // 1
console.log(var2); // 2
console.log(var3); // 3
console.log(var4); // ReferenceError: var4 is not defined
console.log(var5); // ReferenceError: var5 is not defined
```

### 식별자 결정 (identifier resolution)

> 자바스크립트 엔진이 **이름이 같은 두 식별자** 중에 어떤 식별자를 참조해야 할 것인지를 결정하는 것

- 자바스크립트 엔진은 코드를 실행할 때 `코드의 문맥(context)`을 고려
- **코드가 어디서 실행**되며 **주변에 어떤 코드가 있는지**에 따라, 동일한 코드도 다른 결과를 만든다.
  - 이를 `렉시컬(lexical)환경`이라 하며, 코드의 문맥은 렉시컬 환경으로 이뤄진다.
  - 이를 구현한 것이 `실행컨텍스트(execution context)`이며, 모든 코드는 실행컨텍스트에서 평가되고 실행된다.

```cs
var x = "global";

function foo() {
  var x = "local";
  console.log(x); // local
}

foo();
console.log(x); // global

```

- 만약 Scope라는 개념이 없다면 같은 이름을 갖는 변수는 충돌을 일으키므로, 프로그램 전체에서 하나밖에 사용될 수 없다.
  - PC 디렉토리의 파일명은 다른 디렉토리와 중복되어도 상관 없는 거랑 같다.
  - 즉 Scope는 `Namespace`다.

```cs
[ 💡 var와 let, const 의 변수 중복 선언 차이 ]

1️⃣ var 로 선언된 변수는 같은 스코프 내에서 중복 선언이 허용된다.
이는 변수값이 재할당되어 변경되는 부작용을 발생시킨다.

function foo() {
  var x = 1;
  var x = 2; // 자바스크립트 엔진에 의해 var 키워드가 없는 것처럼 동작한다.
  console.log(x);
}
foo();

2️⃣ let, const로 선언된 변수는 같은 스코프 내에서 중복 선언을 허용하지 않는다.

function foo() {
  let x = 1;
  let x = 2; // SyntaxError: Identifier 'x' has already been declared
}
foo();
```

### 13.2 스코프의 종류

---

| 구분 | 설명                  | 스코프      | 변수      |
| ---- | --------------------- | ----------- | --------- |
| 전역 | 코드의 가장 바깥 영역 | 전역 스코프 | 전역 변수 |
| 지역 | 함수 몸체 내부        | 지역 스코프 | 지역 변수 |

- 전역 변수는 어디서든지 참조할 수 있다.
- 지역 변수는 자신의 지역 스코프와 하위 지역 스코프에서 유효하다

### 13.3 스코프 체인

---

- 함수 몸체 내부에서 정의한 함수 : `중첩 함수(nested function)`
- 중첩 함수를 포함하는 함수 : `외부 함수(outer function)`

> 스코프는 **함수의 중첩**에 의해 **계층적 구조**를 갖는다.
> 스코프가 **계층적으로 연결된 것**을 스코프 체인이라 한다.

![함수의 중첩에 의해 계층적 구조를 갖는 스코프 체인](image-1.png)

변수를 참조할 때 자바스크립트 엔진은 **스코프 체인**을 통해 **변수를 참조하는 코드의 스코프에서 시작**하여 상위 스코프 방향으로 이동하며 **선언된 변수를 검색(indetifier resolution)**한다.

![스코프 체인](image.png)

- 스코프 체인은 물리적인 실체로 존재한다.
- 자바스크립트 엔진은 코드(전역 코드와 함수 코드)를 실행하기에 앞서 위 그림과 유사한 자료구조인 **렉시컬 환경을 실제로 생성한다**
  - **변수 선언이 실행**되면 => 변수 식별자가 이 자료구조(렉시컬 환경)에 Key로 등록되고
  - **변수 할당**이 일어나면 => 자료구조의 변수 식별자에 해당하는 값을 변경한다.

```sc
[ 💡 렉시컬 환경 ]

스코프 체인은 실행 컨텍스트의 렉시컬 환경을 단방향으로 연결한 것이다.
전역 렉시컬 환경은 코드가 로드되면 곧바로 생성되고 함수의 렉시컬 환경은 함수가 호출되면 곧바로 생성된다.
```

### 스코프 체인에 의한 변수 검색

> 자바스크립트 엔진은 스코프 체인을 따라 변수를 참조하는 코드의 스코프에서 시작해서
> 상위 스코프의 방향으로 이동하며 선언된 변수를 검색한다.

- 변수를 참조하는 코드의 스코프에서 시작해서 `상위 스코프 방향으로 이동하며` 선언된 변수를 검색한다.

```cs
// 전역 함수
function foo() {
  console.log("global function foo");
}

function bar() {
  // 중첩 함수
  function foo() {
    console.log("local function foo");
  }

  foo(); // 1️⃣ local function foo
}

bar();
```

```cs
1️⃣ 함수 선언문으로 함수를 정의하면 **런타임 이전에 함수 객체가 먼저 생성**된다.
2️⃣ 자바스크립트 엔진은 **함수 이름과 동일한 이름의 식별자를 암묵적으로 선언**하고 생성된 함수 객체를 할당한다.

이처럼 함수도 식별자에 할당되기 때문에 스코프를 갖는다.
```

### 13.4 함수 레벨 스코프

---

- `블록 레벨 스코프(block level scope)`
  - 함수 몸체만이 아니라 모든 코드 블록(**if, for, while, try/catch** 등)이 지역 스코프를 만든다
- `함수 레벨 스코프(function level scope)`
  - 자바스크립트에서 **var 키워드로 선언된 변수** 는 오로지 **함수의 코드블록(함수 몸체)만을 지역 스코프로 인정**한다.
  - let, const는 블록 레벨 스코프를 지원한다.

```cs
[ 💡 var 키워드로 선언된 변수는 함수레벨 스코프만 인정한다. ]

var x = 1;

if (true) {
  // 함수 밖에서 var 키워드로 선언된 변수는 코드 블록 내에서 선언되었다 할지라도 모두 전역변수다.
  // 따라서 아래의 x는 전역변수이며, 이미 선언된 전역변수 x의 값을 재할당한다.
  var x = 10;
}

console.log(x); // 10
```

```cs
var i = 10;

// var 키워드로 선언된 변수는 블록레벨 스코프를 인정하지 않는다
// 따라서 for 문(블록레벨 스코프)에서 선언한 i는 전역 변수다
for(var i = 0; i < 5; i++) {
  console.log(i); // 0 1 2 3 4
}

// 의도치 않게 변수의 값이 변경되었다.
console.log(i); // 5
```

### 13.5 렉시컬 스코프 🔥

---

```cs
var x = 1;

function foo() {
  var x = 10;
  bar(); // 어디서 호출됐는지에 관계없이 함수 자신이 기억하고 있는 전역스코프를 상위 스코프로 사용한다.
}

function bar() { // 어디서 불리든 이 함수 위치 기준으로 상위스코프 설정!
  console.log(x);
}

foo();
bar();

// 1 1
```

- `동적 스코프(dynamic scope)`

  - 함수를 정의하는 시점에는 함수가 어디서 호출될지 알 수 없다.
  - **함수가 호출되는 시점**에 **동적으로 상위 스코프를 결정**해야 하기 때문에 동적 스코프라고 부른다.

- `렉시컬 스코프(lexical scope) = 정적 스코프(static scope)`
  - 상위 스코프가 동적으로 변하지 않고 **함수정의가 평가되는 시점**에 상위 스코프가 정적으로 결정
  - 대부분의 프로그래밍 언어는 렉시컬 스코프를 따른다.
  - **클로저**와 깊은 관계가 있다.

### 함수를 사용하는 이유

---

- `코드의 재사용`
  - 함수를 통해 중복을 제거한다
- `유지보수의 편의성 & 코드의 신뢰성`
- `코드의 가독성`
  - 함수는 객체타입의 값이다.
  - 따라서 이름(식별자)를 붙일 수 있다.
  - 적절한 함수 이름은 함수 내부 코드를 이해하지 않고도 함수의 역할을 파악할 수 있게 돕는다.

### 함수리터럴

---

함수 리터럴은 function 키워드, 함수 이름, 매개 변수 목록, 함수 몸체로 구성된다.

```cs
// 변수에 "함수 리터럴"을 할당
var f = function add(x,y) {
  return x + y;
}
```

```
💡 리터럴
문자 or 약속된 기호를 사용해 값을 생성하는 표기 방식
```

- 함수는 `일급객체`로서 일반객체와는 `호출이 가능하다`는 점에서 다르다.

### 함수 정의 방식

---

1. `함수 선언문`

```cs
function add(x,y) {
  return x + y;
}
```

2. `함수 표현식`

```cs
var add = function add(x,y) {
  return x + y;
};
```

3. `Function 생성자 함수`

```cs
var add = new Function('x', 'y', 'return x + y');
```

4. `화살표 함수(ES6)`

```cs
var add = (x, y) => x + y;
```

```cs
+ "변수" -> 선언(declaration)한다.
+ "함수" -> 정의(definition)한다.
```

### 코드의 문맥에 따른 자바스크립트 엔진의 함수 해석

> 자바스크립트 엔진은 `코드의 문맥` 에 따라 동일한 함수 리터럴을 함수 표현식 or 함수 선언문으로 해석하는 경우가 있다.

- 함수 선언문은 표현식이 아닌 문이므로 변수에 할당할 수 없다.
- 하지만 함수 선언문이 변수에 할당되는 것 처럼 보인다.
  ![함수 선언문은 표현식이 아닌 문이다](image.png)

```cs
var add = function add(x, y) {
  return x + y;
};
```

이렇게 동작하는 이유는 자바스크립트 엔진이 `코드의 문맥`에 따라 `함수리터럴`을

- 표현식이 아닌 문인 `함수 선언문`으로 해석하는 경우
- 표현식인 문인 `함수 리터럴 표현식`으로 해석하는 경우가 있기 때문이다.

### 함수 선언문과 함수 리터럴 표현식

---

> 이 둘은 함수가 생성되는 것은 동일, 다만 호출에서 차이가 있다.

```cs
// 1️⃣ 함수 선언문으로 함수 호출 -> 호출 O
function foo() {
  console.log("foo"); // foo
}
foo();

// 2️⃣ 함수 리터럴 표현식으로 함수 호출 -> 호출 X
(function bar() {
  console.log("bar"); // ReferenceError: bar is not defined
});
bar();
```

#### 함수리터럴

```cs
+ 함수 이름은 함수 몸체 내에서만 참조할 수 있는 식별자다.
+ 함수 몸체 외부에서는 함수 이름으로 함수를 호출할 수 없다는 의미이다.
+ 즉, 함수를 가리키는 식별자가 없다는 것이다.
```

![함수 이름 bar는 함수 몸체 내에서만 참조할 수 있는 식별자이므로 함수를 호출할 수 없다.](image-1.png)

하지만 함수 선언문으로 정의된 함수는 foo라는 이름으로 호출할 수 있었다.
foo는 함수 몸체 내부에서만 유효한 식별자인 함수 이름이므로 호출할 수 없어야 한다.
-> **foo라는 이름으로 함수를 호출하려면** foo는 함수 이름이 아니라 `함수 객체를 가리키는 식별자`여야 한다.

![foo는 자바스크립트 엔진이 암묵적으로 생성한 식별자다.](image-2.png)

자바스크립트 엔진은 생성된 함수를 호출하기 위해 **함수 이름과 동일한 이름의 식별자를 암묵적으로 생성하고**,
거기에 함수 객체를 할당한다.

```cs
// 의사코드(pseudo-code)로 표현하면 이렇다.
var add = function add(x, y) {
  return x + y;
}
```

- 함수는 함수 이름으로 호출하는 것이 아니라 함수 객체를 가리키는 식별자로 호출한다.
- 이 의사코드가 바로 `함수 표현식`이다.

### 함수 표현식

---

- 자바스크립트의 함수는 값처럼 `변수에 할당`할 수도 있고, `프로퍼티 값`이 될 수도 있으며 `배열의 요소`가 될 수도 있다.
- 이처럼 **값의 성질을 갖는 객체**를 `일급 객체`라 한다.

```cs
// 함수 표현식
var add = function (x, y) {
  return x + y;
};
```

- 함수 리터럴의 함수 이름은 생략할 수 있다. = `익명함수`
- 함수 표현식의 함수 리터럴을 익명함수로 사용하는 것이 일반적
- **함수를 호출할 때는 객체를 가리키는 식별자를 사용**해야 한다.

### 함수 생성 시점과 함수 호이스팅

---

```cs
// 함수 참조
console.dir(add); // f add(x, y)
console.dir(sub); // undefined

// 함수 호출
console.log(add(2, 5)); // 7
console.log(sub(2, 5)); // TypeError: sub is not a function

// 함수 선언문
function add(x, y) {
  return x + y;
}

// 함수 표현식
var sub = function(x, y) {
  return x + y;
}
```

- 함수 선언문으로 정의한 함수 = 함수 선언문 이전에 호출 O.
- 함수 표현식으로 정의한 함수 = 함수 표현식 이전에 호출 X.

=> **함수의 생성 시점이 다르다.**

### 함수 호이스팅

> 함수를 호출하기 전에 반드시 함수를 선언해야 한다는 당연한 규칙을 무시하므로
> `함수 표현식`을 사용할 것을 권장.

1. `함수 선언문`

```cs
+ 런타임 이전에 `함수 객체가 먼저 생성`된다.
+ 자바스크립트 엔진은 함수 이름과 동일한 이름의 `식별자를 암묵적으로 생성`하고, `생성된 함수 객체를 할당`한다.
+ 즉, 코드가 한줄씩 실행되는 런타임에는 이미 생성과 할당이 되어 있다 => 호출 가능
```

2. `함수 표현식`

```cs
+ 변수에 할당되는 값이 함수 리터럴인 문이다.
+ 변수 선언은 런타임 이전에 실행되어 undefined로 초기화 된다.
+ 변수 할당문의 값은 할당문이 실행되는 시점, 즉 런타임에 평가된다.
+ 따라서 함수 표현식으로 정의하면 함수 호이스팅이 아니라 변수 호이스팅이 발생한다 => 호출 불가
```

### Function 생성자 함수

자바스크립트가 기본 제공하는 빌트인 함수인 **Function 생성자 함수**에 매개변수 목록과 함수 몸체를 문자열로 전달하면서,
new 연산자와 함께 호출하면 **함수 객체를 생성해서 반환**한다.

```cs
💡 생성자 함수
+ 객체를 생성하는 함수를 말한다
```

```cs
var add = new Function('x', 'y', 'return x + y');
```

- Function 생성자 함수로 함수를 생성하는 방식은 일반적이지 않으며 바람직하지도 않다.
- Function 생성자 함수로 생성한 함수는 `클로저를 생성하지 않는` 등, 함수 선언문이나 함수 표현식으로 생성한 함수와 다르게 동작한다.

```cs
var add1 = (function () {
  var a = 10;
  return function (x, y) {
    return x + y + a;
  };
}());

console.log(add1(1, 2)); // 13

var add2 = (function () {
  var a = 10;
  return new Function('x', 'y', 'return x + y + a;');
}());

console.log(add1(1, 2)); // ReferenceError: a is not defined
```

### 화살표 함수

- ES6: function 키워드 대신 화살표(fat arrow =>)를 사용해 더 간략한 방법으로 선언
- 항상 익명함수로 정의한다
- 내부동작 또한 간략화되어 있다.
- 생성자 함수로 사용할 수 없으며, 기존 함수와 this 바인딩 방식이 다르고, prototype 프로퍼티가 없으며 arguments 객체를 생성하지 않는다.

```cs
// 화살표 함수
const add = (x, y) => x + y;
console.log(add(2, 5)); // 7
```

### 12.5 함수 호출

---

- 매개변수(parameter)는 함수 몸체 내부에서만 참조할 수 있다.
  - 즉, 매개변수의 스코프(유효 범위)는 함수 내부다.

```cs
function add(x, y) {
  return x + y;
}

console.log(x, y); // ReferenceError: x is not defined
// add 함수의 매개변수 x, y는 함수 몸체 내부에서만 참조할 수 있다.
```

- 함수는 매개변수와 인수의 개수가 일치하는지 체크하지 않는다. (에러가 나지 않음)
- 인수가 부족해서 할당되지 않는 매개 변수의 값은 Undefined다.

```cs
function add(x, y) {
  return x + y;
}

console.log(add(2)); // NaN
```

- 인수는 암묵적으로 arguments 객체의 프로퍼티로 보관된다.
- arguments 객체는 함수를 정의할 때 매개변수 개수를 확정할 수 없는 가변 인자 함수를 구현할 때 유용하게 사용된다

```cs
function add(x, y) {
  console.log(arguments);

  return x + y;
}

console.log(2, 5, 10);
```

### 인수 확인이 필요한 자바스크립트

```cs
1️⃣ 자바스크립트 함수는 매개변수와 인수의 개수가 일치하는지 확인하지 않는다.
2️⃣ 자바스크립트는 "동적 타입 언어"다. 따라서 자바스크립트 함수는 매개변수의 "타입을 사전에 지정할 수 없다."
```

따라서, 자바스크립트의 경우 함수를 정의할 때, 인수가 전달되었는지 확인할 필요가 있다.

```cs
1. typeof 연산자 를 사용하는 방법
2. 인수가 전달되지 않은 경우 단축 평가 를 사용하는 방법
3. 매개변수에 기본값(default value) 을 할당하는 방법
4. 정적 타입 선언 이 가능한 Typescript 사용하는 방법
```

```cs
// 1️⃣ typeof 연산자로 arguments 문제 방지
function add(x, y) {
  if (typeof x !== "number" || typeof y !== "number") {
    throw new TypeError("인수는 모두 숫자(number)값 이어야 합니다.");
  }

  return x + y;
}
console.log(add(1, 2)); // 3
console.log(add(2)); // TypeError: 인수는 모두 숫자(number)값 이어야 합니다.
console.log(add("a", "b")); // TypeError: 인수는 모두 숫자(number)값 이어야 합니다.

// 2️⃣ "단축 평가"로 arguments 문제 방지
function mul(a, b, c) {
  a = a || 1;
  b = b || 1;
  c = c || 1;

  return a * b * c;
}
console.log(mul(1, 2, 3)); // 6
console.log(mul(1, 2)); // 2
console.log(mul(1)); // 1
console.log(mul()); // 1

// 3️⃣ parameter default value 설정으로 argument 문제 방지 (ES6 도입)
// 인수를 전달하지 않았거나, undefined를 전달했을 경우해만 사용
function sub(a = 0, b = 0) {
  return a - b;
}
console.log(sub(10, 9)); // 1
console.log(sub(10)); // 10
console.log(sub()); // 0

```

### 값에 의한 호출 vs 참조에 의한 호출

---

- `값에 의한 호출(call by value)` : 함수 호출시 매개변수에 `원시 값(primitive value)`을 전달
- `참조에 의한 호출(call by reference)` : 함수 호출시 매개변수에 `객체(object)` 를 전달

#### 값에 의한 호출

- 원시 값은 `변경 불가능한 값(immutable value)` 성질
- 즉, 원시 타입의 argument 는 `값 자체가 복사되어 매개변수에 전달`
- 이 값을 변경(재할당을 통한 변경)해도 `원본은 훼손되지 않는다`. ( side effect X )

#### 참조에 의한 호출

- 객체는 `변경 가능한 값(mutable value)` 성질
- 즉, 객체 argument 는 `참조 값이 복사되어 매개변수에 전달`
- 참조 값을 통해 전달한 객체를 변경할 경우 `원본이 훼손된다`. ( side effect O )

```cs
[ 💩 참조에 의한 호출의 문제점 ]

= 객체가 변경될 수 있기 때문에 "상태 변화 추적"이 어렵다.

[ ✅ 문제 해결 방법 ]

- 객체를 불변 객체(immutable object)로 만들어 사용하는 것
- 상태 변경이 필요한 경우에는 객체의 방어적 복사(defensive copy)를 통해 원본 객체를 완전히 복제,
- 즉, 깊은 복사를 통해 새로운 객체를 생성하고 재할당을 통해 교체한다.

[ 💡 함수형 프로그래밍 ]

- 순수함수 = 외부 상태를 변경하지 않고, 외부상태에 의존하지도 않는 함수
순수 함수를 통해 side effect를 최대한 억제하여 오류를 피하고
프로그램의 안정성을 높이려는 프로그래밍 패러다임

```

```cs
function changeVal(primitive, obj) {
  primitive += 100;
  obj.name = "Lee";
}

// 외부 상태
var num = 100; // 원시 값
var person = { name: "Kim" }; // 객체

console.log(num); // 100
console.log(person); // { name: 'Kim' }

changeVal(num, person);

console.log(num); // 100
console.log(person); // { name: 'Lee' } 💩
```

### 다양한 함수의 형태

1. `즉시 실행 함수 (IIFE, Immediately Invoked Function Expression)`

함수 정의와 동시에 즉시 호출되는 함수.
단 한 번만 호출되며 다시 호출할 수 없다.

- 주로 익명함수를 사용한다.
- 기명함수도 가능은 하지만 호출은 불가함.
- 반드시 그룹 연산자 `(...)`로 감싸야 한다. 그렇지 않으면 에러 발생

```cs
// 익명함수
(function () {
  var a = 3;
  var b = 5;
  return a + b;
}());

//
```

2. `재귀 함수(recursive function)`

자기 자신을 호출하는 함수. 반복문(for, while)으로 사용 가능

- 탈출 조건을 반드시 만들어야 한다. (stack overflow)

```cs
function countdown(n) {
  if(n < 0) return;
  console.log(n);
  countdown(n - 1); // 재귀 호출
}

countdown(10);
```

3. `중첩 함수(nested function) == 내부 함수(inner function)`

중첩 함수는 외부 함수 내부에서만 호출할 수 있다.

- 중첩 함수는 자신을 포함하는 외부 함수를 돕는 헬퍼 함수(helper function) 역할을 한다.

```cs
function outer() {
  var x = 1;

  // 중첩 함수 == 내부 함수
  function inner() {
    var y = 2;

    // 외부 함수의 변수 참조
    console.log(x + y); // 3
  }

  inner();
}

outer();
```

4. `콜백 함수(callback function)`

함수의 매개변수(parameter)를 통해 다른 함수의 내부로 전달되는 함수

```cs
// 외부에서 전달받은 func 를 n 만큼 반복 호출 - 고차 함수 (HOF)
function repeat(n, f) {
  for (var i = 0; i < n; i++) {
    f(i);
  }
}

// 콜백 함수 정의 - logAll
var logAll = function (i) {
  console.log(i);
};

// 반복 호출할 함수를 인수로 전달
repeat(5, logAll); // 0 1 2 3 4
```

- 콜백 함수는 고차 함수에 의해 호출된다.
- 고차 함수는 필요에 따라 **콜백 함수에 인수(argument)를 전달**할 수 있다.
  - 그렇기 때문에 고차함수에 콜백함수 전달 시 **콜백 함수를 호출하지 않고 함수 자체를 전달**해야 함
- 함수는 `일급 객체` 이므로 **함수의 매개변수를 통해 함수를 전달 가능**
  - 함수는 더 이상 내부로직에 강력히 의존하지 않고 외부에서 로직의 일부분을 함수로 전달받아 수행하므로 유연한 구조를 갖는다

### 10.1 객체란?

---

> 자바스크립트는 `객체(object)` 기반의 프로그래밍 언어

- [원시값(primitive value)](https://developer.mozilla.org/ko/docs/Glossary/Primitive) 을 제외한 나머지 값( 함수, 배열, 정규 표현식 등 )은 모두 객체
- 원시 타입은 하나의 값만 나타내지만 `객체 타입(object / reference type)` 은 `다양한 타입의 값(원시 값 또는 다른 객체)`을 하나의 단위로 구성
- 원시값은 `변경 불가(immutable)` 한 값이지만, 객체는 `변경 가능(mutable)` 한 값
- 객체는 0개 이상의 `프로퍼티(property)` 로 구성된 집합이며, 프로퍼티는 `키(key) : 값(value)` 로 구성
- 자바스크립트에서 `함수(function)` 도 프로퍼티의 값으로 설정가능 → `메서드(method)`

```cs
var counter = {
	num: 0,  // 프로퍼티
  increase: function () { ... )  // 메서드
}
```

```s
[ 💡 NOTE ]

프로퍼티(property) = 객체의 상태를 나타내는 값(data)
메서드(method) = 프로퍼티(상태 데이터)를 참조하고 조작할 수 있는 동작(behavior)
```

### 10.2 객체 리터럴에 의한 객체 생성

---

1. 객체지향 언어(ex. C++, Java)는 클래스를 사전에 정의한다.
2. 필요한 시점에 new 연산자와 함께 생성자(constructor)를 호출하여 인스턴스를 생성하는 방식으로 객체를 생성한다.

```s
[ 💡 인스턴스 ]
+ 클래스에 의해 생성되어 메모릴에 저장된 실체
+ 객체지향 프로그래밍에서 객체는 클래스와 인스턴스를 포함한 개념.
+ 클래스는 인스턴스를 생성하기 위한 템플릿의 역할을 한다.
+ 인스턴스는 객체가 메모리에 저장되어 실제로 존재하는 것에 초점을 맞춘 용어
```

> 자바스크립트는 프로토타입 기반 객체지향 언어
> 자바와 같은 클래스 기반 객체지향 언어와는 달리 다양한 객체 생성 방법을 지원한다.

- `객체 리터럴`
- `Object 생성자 함수`
- `생성자 함수`
- `Object.create 메서드`
- `클래스(ES6)`

> 객체리터럴: 중괄호({...})내에 0개 이상의 프로퍼티를 정의한다.
> 변수에 할당되는 시점에 자바스크립트 엔진은 객체 리터럴을 해석해 객체를 생성한다

- 자바스크립트의 유연함과 강력함을 대표하는 객체 생성 방식
- 객체를 생성하기 위해 클래스를 먼저 정의하고 new 연산자와 함께 생성자를 호출할 필요가 없다.

### 10. 3 프로퍼티

---

> 객체는 프로퍼티의 집합, 프로퍼티는 키와 값으로 구성된다.

```cs
var person = {
  // 프로퍼티 키는 name, 프로퍼티 값은 'Lee'
  name: 'Lee',
  age: 20
}
```

- 프로퍼티 `키(key)` : 빈 문자열( '' ) 을 포함하는 모든 `문자열(string)` 또는 `심벌(symbol)` 값
- 프로퍼티 `값(value)` : 자바스크립트에서 사용할 수 있는 모든 값

> 프로퍼티 키는 프로퍼티 값에 접근할 수 있는 이름으로서 `식별자 역할`

- 하지만 반드시 식별자 네이밍 규칙 을 따라야 하는 것은 아니다.
- 자바스크립트에서 사용 가능한 유요한 이름인 경우, 따옴표( '' or "") 를 생략할 수 있다.
- 반대로 말하면 식별자 네이밍 규칙을 따르지 않는 이름에는 반드시 따옴표를 사용해야 한다.

```cs
var person = {
	firstName: 'Ung-mo',  // 식별자 네이밍 규칙을 준수한 프로퍼티 키
	'last-name': 'Lee',       // 식별자 네이밍 규칙을 준수하지 않은 프로퍼티 키 ( 따옴표를 사용해 문자열 형태 유지 )
  last-name: 'Lee'          // SyntaxError: Unexpected token ( 식별자 네이밍 규칙을 준수하지 않은 프로퍼티 키 ( 따옴표를 사용하지 않을 경우 - 표현식으로 해석 ) )
};
```

- 문자열 또는 문자열로 평가할 수 있는 표현식을 사용해 프로퍼티 키를 동적으로 생성할 수도 있다.
- 이 경우에는 프로퍼티 키로 사용할 표현식을 대괄호([...])로 묶어야 한다.

```cs
var obj = {};
var key = 'hello';

// ES5: 프로퍼티 키 동적 생성
obj[key] = 'hello';
// ES6: 계산된 프로퍼티 이름
// var obj = {[key]:'world'};

console.log(obj); // {hello: 'world'}
```

- 프로퍼티에 문자열이나 심벌 값 외의 값을 사용하면 암묵적 타입 변환 을 통해 문자열이 된다.

```cs
var foo = {
  0: 1,
  1: 2,
  2: 3,
};

console.log(foo); // { '0': 1, '1': 2, '2': 3 } << 키값이 문자열 형태로 암묵적 타입 변환

```

- var, function같은 예약어를 프로퍼티 키로 사용해서 에러가 발생하지는 않는다.
- 하지만 예상치못한 에러가 발생할 여지가 있으므로 권장하지 않는다.

- 이미 존재하는 프로퍼티 키를 중복 선언하면 나중에 선언한 프로퍼티가 먼저 선언한 프로퍼티를 덮어쓴다. ( 에러 발생하지 않음 )

```cs
var foo = {
  name: 'Lee',
  name: 'Kim
}

console.log(foo); // {name: 'Kim'}
```

### 10.4 메서드

---

- 프로퍼티 값이 함수일 경우 일반함수와 구분하기 위해 method라 부른다.

### 10.5 프로퍼티 접근

---

- 마침표(.) 프로퍼티 접근 연산자를 사용하는 방법 -> 마침표 표기법 (dot notation)
- 대괄호([...]) 프로퍼티 접근 연산자를 사용하는 방법 -> 대괄호 표기법(bracket notation)`

```cs
console.log(person.name); // "WI" ( 마침표 표기법 )
console.log(person["name"]); // "WI" ( 대괄호 표기법 )

// 💩 대괄호 프로퍼티 접근 연산자 내에 문자열 형태가 아닌 프로퍼티 키로 사용하면 자바스크립트 엔진은 "식별자"로 해석
console.log(person[name]); // ReferenceError: name is not defined

// 💩 객체에 존재하지 않는 프로퍼티에 접근시 -> undefined
console.log(person.age); // undefined

```

- 프로퍼티 키가 식별자 네이밍 규칙을 준수하지 않는 이름이면, 반드시 대괄호 표기법을 사용해야 한다.

```c
person.'last-name'; // SyntaxError: Unexpected string
person.last-name; // 브라우저 환경: NaN
                  // node.js 환경: ReferenceError: name is not defined
person[last-name]; // referenceError: last is not defined
person['last-name']; // Lee
```

- 프로퍼티 키가 숫자로 이뤄진 문자열인 경우 따옴표를 생략할 수 있다.

```c
[ 💡 Note ]
브라우저환경에는 전역객체 window의 프로퍼티 name이 있다.
때문에 Node.js 환경과 브라우저내의 에러가 다르다.
```

### 10.6 ~ 10.8 프로퍼티 동적 생성 & 삭제

---

```cs
var person = {
  name: "Lee",
};

person.name = 'Kim';
// person 객체에 Name 프로퍼티가 존재하므로 name 프로퍼티의 값이 갱신된다.
console.log(person); // { name: 'Kim' }

person.age = 20;
// age프로퍼티가 존재하지 않는다.
// age 프로퍼티가 동적으로 생성되고 값이 할당된다.

delete person.age;
// age 라는 프로퍼티 키가 있고 -> 해당 프로퍼티 삭제
delete person.job;
// job 이라는 프로퍼티 키는 없음 -> 에러는 발생하지 않음

```

### 10.9 ES6에서 추가된 객체 리터럴의 확장 기능

---

### 프로퍼티 축약표현

- `ES5`

```cs
var x = 1, y = 2;

var obj = {
  x: x,
  y: y
}

console.log(obj); // {x: 1, y:2}
```

- `ES6`

```cs
let x = 1, y = 2;

// 프로퍼티 축약 표현
const obj = { x, y };

console.log(obj); {x:1, y:2}
```

### 계산된 프로퍼티 이름

- `ES5`

```cs
var prefix = "prop";
var i = 0;

var obj = {};

// "계산된 프로퍼티 이름"으로 프로퍼티 키 동적 생성
obj[prefix + "-" + ++i] = i;
obj[prefix + "-" + ++i] = i;
obj[prefix + "-" + ++i] = i;

console.log(obj); // { 'prop-1': 1, 'prop-2': 2, 'prop-3': 3 }
```

- `ES6`

```cs
const prefix = "prop";
let i = 0;

// "객체 리터럴 내부"에서 계산된 프로퍼티 이름으로 프로퍼티 키를 동적 생성
const obj = {
  [`${prefix}-${++i}`]: i,
  [`${prefix}-${++i}`]: i,
  [`${prefix}-${++i}`]: i,
};

console.log(obj); // { 'prop-1': 1, 'prop-2': 2, 'prop-3': 3 }

```

### 메서드 축약 표현

- `ES5`

```cs
var obj = {
  name: "Lee",

  // 프로퍼티 값으로 "함수를 할당"
  sayHi: function () {
    console.log(`Hi! ${this.name}`);
  },
};

obj.sayHi(); // Hi! Lee
```

- `ES6`
  - 단, 메서드 축약 표현 으로 정의한 메서드는 프로퍼티에 할당한 함수(ES5) 와 다르게 동작한다.

```cs
const obj = {
  name: "Lee",

  // 메서드 축약 표현 ( 함수 선언식 필요 X )
  sayHi() {
    console.log(`Hi! ${this.name}`);
  },
};

obj.sayHi(); // Hi! Lee

```

### 제어문 개요

---

> 제어문은 조건에 따라 코드 블록을 실행(조건문)하거나 반복실행(반복문)할 때 사용한다.

- 제어문은 코드의 실행 흐름을 인위적으로 제어할 수 있다. → 순자적으로 진행하는 직관적인 코드의 흐름을 혼란스럽게 만든다.
- 즉, 제어문은 코드의 흐름을 이해하기 어렵게 만들어 가독성을 해치는 단점 이 있다. → 가독성이 좋지 않은 코드는 오류를 발생시키는 원인

```c
+ forEach()
+ map()
+ filter()
+ reduce()

같은 "고차 함수"를 사용한 "함수형 프로그래밍 기법"에서는 제어문의 사용을 억제하여 복잡성을 해결하려고 노력한다.

```

### 8.1 블록문

---

블록문은 0개 이상의 문을 중괄호로 묶은 것.

**특징**

- 언제나 문(statement)의 종료를 의미하는 자체 종결성을 갖기 때문에 세미콜론을 붙이지 않는다.

```cs
{
  var foo = 10;
}
```

### 8.2 조건문

---

- `if..else` 와 `switch`문으로 제공한다.

### 8.2.1 if...else

- if문의 조건식은 boolean 값으로 평가되어야 한다.
- 코드 블록 내에의 문이 하나뿐이라면 중괄호를 생략할 수 있다.
- 삼항 조건 연산자로 바꿔 쓸 수 있고, 삼항 연산자는 값으로 평가되는 표현식이다. 따라서 변수로 할당할 수 있다.

```cs
if(조건식) {

}

if(num > 0) kind = "양수";

// 조건에 따라 단순히 값을 결정하여 변수에 할당하는 경우 삼항 조건 연산자를 사용하는 편이 가독성이 좋다.
var kind = num ? (num > 0 ? '양수' : '음수') : '명';
```

### 8.2.2 switch

- switch문은 주어진 표현식을 평가하여 그 값과 일치하는 표현식을 갖는 case문으로 실행 흐름을 옮긴다.

- `if...else` 조건식: boolean값으로 평가
- `switch` 표현식: 문자열이나 숫자값인 경우가 많음

**💡폴스루(fall through)**

> 문을 실행한 후 switch문을 탈출하지 않고 모든 case와 default문을 실행하는 것

- 기본적으로 case문에는 break문을 추가해야 한다.

**break 문을 생략한 폴스루가 유용한 경우**

- 여러개의 case문을 하나의 조건으로 사용하기

```cs
// 윤년 계산
swtich (month) {
	case 1: case 3: case 5: case 7: case 8: case 10: case 12:
		days = 31;
		break;
	case 4: case 6: case 9: case 11:
		days = 30;
		break;
	case 2:
		days = ((year % 4 === 0 || year % 100 !== 0) || (year % 400 === 0)) ? 29 : 28;
		break;
	default:
		console.log("Invaild month");
}
```

- case, default, break등 다양한 키워드를 사용해야 하고, 폴스루가 발생하는 등 문법도 목잡하다.
- 따라서 `if..else`문으로 해결할 수 있다면 `switch`문 보다 `if..else`문을 사용하는 편이 좋다.
- 조건식이 너무 많아서 가독성이 떨어지는 경우 `switch`를 사용한다.

### 8.3 반복문 (loop statement)

---

- 자바스크립트는 `for`, `while`, `do..while`문을 제공한다.

**💡반복문을 대체할 수 있는 다양한 기능**

- `forEach`: 배열을 순회할 때 사용
- `for..in`: 객체의 프로퍼티를 열거할 때 사용
- `for..of`: ES6에서 도입된 이터러블을 순회할 수 있음

### 8.3.1 for 문

for문은 조건식이 거짓으로 평가될 때까지 코드 블록을 반복 실행한다.

```c
for(변수 선언문 또는 할당문; 조건식; 증감식) {
  조건식이 참인 경우 반복 실행될 문;
}
```

![for문의 실행순서](image.png)

```cs
1️⃣ for문을 실행하면 먼저 변수선언문 var i = 0이 실행된다.
변수 선언문은 단 한 번만 실행된다.

2️⃣ 변수 선언문의 실행이 종료되면 조건식이 실행된다.
현재 i 변수의 값은 0이므로 조건식의 평가 결과는 true다.

3️⃣ 조건식의 평가 결과가 true이므로 코드 블록이 실행된다.
증감문으로 실행 흐름이 이동하는 것이 아니라 코드 블록으로 실행 흐름이 이동하는 것에 주의하자.

4️⃣ 코드 블록의 실행이 종료되면 증감식 i++가 실행되어 i 변수의 값은 1이 된다.

5️⃣ 증감식 실행이 종료되면 다시 조건식이 실행된다.
변수 선언문이 실행되는 것이 아니라 조건식이 실행된다는 점에 주의하자
(앞에서 설명했지만 변수 선언문은 단 한 번만 실행된다.)
현재 i 변수의 값은 1이므로 조건식의 평가 결과는 true다.
```

- for문의 변수 선언문, 조건식, 증감식은 모두 옵션이므로 반드시 사용할 필요는 없다.
- 단, 어떤 식도 선언하지 않으면 무한루프가 된다.

```c
for (;;) { ... } //무한루프
```

### 8.3.2 while 문

- 주어진 조건식의 평가 결과가 참이면 코드 블록을 계속해서 반복 실행한다.
- while문은 조건문의 평가 결과가 거짓이 되면 코드 블록을 실행하지 않고 종료한다.
- 무한 루프에서 탈출하기 위해서는 코드 블록 내에 `if`문으로 탈출 조건을 만들고 `break`문으로 탈출한다.

```c
while(true) {
  count++;
  if(count === 3) break;
}
```

### 8.3.3 do...while 문

코드 블록을 먼저 실행하고 조건식을 평가한다.

```cs
// count가 3보다 작을 때까지 코드 블록을 반복 실행한다.

var count = 0;

do {
  console.log(count); // 0 1 2
  count ++;
} while (count < 3);
```

### 8.4 break문

---

- 레이블 문, 반복문, 또는 switch 문의 코드블록을 탈출한다. 이 외의 블록에 break문을 사용하면 SyntaxError가 발생한다.

**❓레이블문**

- 식별자가 붙은 문

```cs
// foo라는 레이블 식별자가 붙은 레이블 문
foo: console.log('foo');
```

- 프로그램의 실행 순서를 제어하는 데 사용한다.
- switch문의 `case`문과 `default`문도 레이블 문이다.
- 레이블 문을 탈출하려면 break문에 레이블 식별자를 지정한다.

```cs
foo: {
  break foo;
}
```

- 내부 for문에서 break문을 실행하면 탈출하여 외부 for문으로 진입한다.
- 내부 for문이 아닌 `외부 for문을 탈출하려면` 레이블 문을 사용한다

```cs
outer: for() {
  for() {
    if(i + j === 3) break outer;
  }
}
```

- 레이블 문은 중첩된 for 문 외부로 탈출 할 때 유용하지만 그 외에는 일반적으로 권장하지 않는다.
- 레이블 문 사용시 → 프로그램의 흐름이 복잡해져서 가독성이 나빠지고 오류를 발생시킬 가능성이 높아지기 때문 ( 존재 정도만 인지할 것 )

### 8.5 Continue 문

---

> continue 문 은 반복문의 코드 블록 실행을 현 시점에서 중단하고 ,
> 반복문의 증감식으로 실행 흐름을 이동시킨다. ( break 문처럼 반복문을 탈출하지는 않는다. )

```cs
// for (var i = 0; i < string.length; i++) {
  // search값이 아니면 현 지점에서 실행을 중단하고 반복문의 증감식으로 이동한다.
  if(string[i] !== search) continue;
  count++; // continue문이 실행되면 이 문은 실행되지 않는다.
}
```

- if 문 내에서 `실행해야 할 코드가 길다면` → `들여쓰기가 한 단계 더 깊어지므로` , continue 문을 사용하는 편이 가독성이 더 좋을 수 있다.

```cs
// if문 내에서 여러 코드 작성해야 할 경우 -> continue 문을 사용하지 않았을 경우
var arr = [1, 2, 3, 4, 5];
var target = 3;
var count = 0;

for (var i = 0; i < arr.length; i++) {
  // arr[i] 가 target 이하라면 count 증감
  if (arr[i] <= target) {
    count++;
    // code...
    // code...
    // code...
  }
}

// if문 내에서 여러 코드 작성해야 할 경우 -> continue 문을 사용한 경우 -> depth가 하나 줄어들었다.
var arr = [1, 2, 3, 4, 5];
var target = 3;
var count = 0;

for (var i = 0; i < arr.length; i++) {
  // arr[i] 가 target 초과이면 count 증감하지 않는다.
  if (arr[i] > target) continue;

  count++;
  // code...
  // code...
  // code...
}
```

